// Skip screening: pass articles through with default Maybe decision
const articles = $('Input').all().map(i => i.json);
console.log('Screening SKIPPED: ' + articles.length + ' articles passed through with decision=Maybe');
return articles.map(a => ({ json: { ...a, screening_decision: 'Maybe', screening_reason: 'Screening skipped by user', screening_color: 'orange' } }));

// === SCREENING v3 - Prompt simplifie + batches reduits ===
const items = $input.all();
const articles = items.map(i => i.json);
const BATCH_SIZE = 3;
const question = (articles[0] && articles[0].question) || '';
const criteria = (articles[0] && articles[0].criteria) || '';
// (A3) Reglages IA personnalises injectes par l'UI dans articles[0]._ai_settings
const aiSettings = (articles[0] && articles[0]._ai_settings) || {};
const strictness = (typeof aiSettings.strictness === 'number') ? aiSettings.strictness : 50;
const customRules = (aiSettings.custom_rules || '').toString().trim();
// Mapping strictesse -> indication au LLM
let strictnessGuidance = '';
if (strictness <= 25) {
  strictnessGuidance = '\n\n=== TONE GUIDANCE ===\nBe CONSERVATIVE: when in doubt, prefer Include or Maybe over Exclude. The user wants to capture as many potentially relevant articles as possible at this stage.';
} else if (strictness >= 75) {
  strictnessGuidance = '\n\n=== TONE GUIDANCE ===\nBe STRICT: only mark Include if all criteria are clearly met. When in doubt, prefer Exclude. The user wants a tightly filtered set of highly relevant articles.';
} else if (strictness >= 60) {
  strictnessGuidance = '\n\n=== TONE GUIDANCE ===\nBe slightly strict: when in doubt, lean toward Exclude rather than Maybe.';
} else if (strictness <= 40) {
  strictnessGuidance = '\n\n=== TONE GUIDANCE ===\nBe slightly conservative: when in doubt, lean toward Maybe rather than Exclude.';
}
const customRulesBlock = customRules
  ? '\n\n=== USER-DEFINED RULES (must be respected) ===\n' + customRules
  : '';
const batches = [];

function sanitize(text) {
  return (text || '').replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, ' ').replace(/\s+/g, ' ').trim();
}

for (let i = 0; i < articles.length; i += BATCH_SIZE) {
  const batch = articles.slice(i, i + BATCH_SIZE);
  const articleList = batch.map((a, j) => {
    const title = sanitize(a.title || 'No title').substring(0, 120);
    const abstract = sanitize(a.abstract || 'No abstract').substring(0, 400);
    return '[' + j + '] TITLE: ' + title + '\nABSTRACT: ' + abstract;
  }).join('\n\n');

  const prompt = `You are a systematic review screener. Decide for each article: Include / Maybe / Exclude.\n\nRESEARCH QUESTION:\n${sanitize(question).substring(0, 500)}\n\nINCLUSION/EXCLUSION CRITERIA:\n${sanitize(criteria).substring(0, 500)}\n\n=== ARTICLES TO SCREEN ===\n${articleList}\n\n=== DECISION RULES ===\n- Include = ALL inclusion criteria clearly met AND no exclusion criterion applies (population, study type, period, language all match)\n- Maybe = at least one criterion is unclear from the abstract OR the abstract is too brief to decide\n- Exclude = clearly fails at least one inclusion criterion OR clearly meets an exclusion criterion\n\nWhen genuinely uncertain: choose Maybe (be inclusive at this stage).\n\n=== OUTPUT FORMAT ===\nReturn ONLY a JSON object with this exact structure (no markdown, no extra text):\n{"decisions":[{"index":0,"decision":"Include","reason":"brief justification mentioning which criteria match"}]}\n\nProvide one entry per article, indexes 0 to ${batch.length - 1}. The decision field MUST be exactly "Include", "Maybe", or "Exclude".${strictnessGuidance}${customRulesBlock}`;

  batches.push({ json: { prompt, batchIndex: Math.floor(i / BATCH_SIZE), batchSize: batch.length } });
}

console.log('Screening v3: ' + articles.length + ' articles -> ' + batches.length + ' batches de ' + BATCH_SIZE);
return batches;

// === EXPAND v3 - Parser JSON robuste ===
const responses = $input.all();
const originalItems = $('Input').all();
const articles = originalItems.map(i => i.json);
const BATCH_SIZE = 3;
const colorMap = { 'Include': 'green', 'Maybe': 'orange', 'Exclude': 'red' };

function extractJson(text) {
  if (!text) return null;
  text = text.replace(/```json\s*/gi, '').replace(/```\s*/g, '');
  const start = text.indexOf('{');
  if (start === -1) return null;
  let depth = 0, inString = false, escape = false;
  for (let i = start; i < text.length; i++) {
    const c = text[i];
    if (escape) { escape = false; continue; }
    if (c === '\\') { escape = true; continue; }
    if (c === '"') { inString = !inString; continue; }
    if (inString) continue;
    if (c === '{') depth++;
    else if (c === '}') {
      depth--;
      if (depth === 0) {
        try { return JSON.parse(text.substring(start, i + 1)); } catch(e) { return null; }
      }
    }
  }
  return null;
}

const results = [];
let totalInc = 0, totalExc = 0, totalMay = 0;
let okBatches = 0, failedBatches = 0;
const diagnostics = [];

for (let r = 0; r < responses.length; r++) {
  const resp = responses[r].json || {};
  let decisionMap = {};
  let batchOk = false;

  if (resp.response) {
    const parsed = extractJson(resp.response);
    if (parsed && Array.isArray(parsed.decisions)) {
      // (Fix 2026-05-19) Tolerer index manquant : assumer ordre sequentiel du batch.
      // Avant : on dropait les decisions sans index -> beaucoup d'articles en "Index missing".
      parsed.decisions.forEach((d, autoIdx) => {
        const idx = (d.index !== undefined) ? d.index : autoIdx;
        let decision = (d.decision || 'Maybe').toString().trim();
        // Normaliser vers Include/Maybe/Exclude (tolere variations de casse)
        const lower = decision.toLowerCase();
        if (lower.startsWith('inc')) decision = 'Include';
        else if (lower.startsWith('exc')) decision = 'Exclude';
        else decision = 'Maybe';
        decisionMap[idx] = { decision, reason: d.reason || '' };
      });
      batchOk = Object.keys(decisionMap).length > 0;
    } else {
      diagnostics.push('Batch ' + r + ' parse failed - response starts: ' + (resp.response || '').substring(0, 200));
    }
  } else if (resp.error) {
    diagnostics.push('Batch ' + r + ' API error: ' + (resp.error.message || resp.error).toString().substring(0, 100));
  } else {
    diagnostics.push('Batch ' + r + ' empty response');
  }

  if (batchOk) okBatches++; else failedBatches++;

  const start = r * BATCH_SIZE;
  const end = Math.min(start + BATCH_SIZE, articles.length);
  for (let i = start; i < end; i++) {
    const localIdx = i - start;
    const decision = decisionMap[localIdx] !== undefined ? decisionMap[localIdx].decision : 'Maybe';
    if (decision === 'Include') totalInc++;
    else if (decision === 'Exclude') totalExc++;
    else totalMay++;
    results.push({
      json: {
        ...articles[i],
        screening_decision: decision,
        screening_reason: decisionMap[localIdx] !== undefined ? decisionMap[localIdx].reason : (batchOk ? 'Index missing in response' : 'Batch failed - defaulted to Maybe'),
        screening_color: colorMap[decision] || 'orange'
      }
    });
  }
}

console.log('=== Screening v3 complete ===');
console.log('Articles: ' + results.length + ' | Batches OK: ' + okBatches + ' | Batches KO: ' + failedBatches);
console.log('Decisions: Include=' + totalInc + ' Maybe=' + totalMay + ' Exclude=' + totalExc);
if (diagnostics.length > 0) {
  console.log('--- Diagnostics ---');
  diagnostics.slice(0, 3).forEach(d => console.log(d));
}
return results;
